<template>
  <div class="main">
    <div class="content">
    

      <Nav index = '1'></Nav>
      <div class="show_wrap">
              <h1 class='titleh1'>
              <b class='lef'></b>
              <b class='rig'></b>
              {{data["еҢ»йҷўеҗҚз§°"]}}
              </h1>
        <div class="row height55">
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <div class="line a"></div>
              <h4 class="card_title">и®ҫеӨҮең°еқҖ</h4>
              <div class="card_show">
                <div class="img_map" id ='allmap'>
            
                </div>
              </div>
            </div>
          </div>
          <div class="col">
            <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
               <h4 class="card_title">и®ҫеӨҮдҝЎжҒҜ</h4>
              <div class="card_show"> 
                <div class="model_table">
                  <div class="col" v-for='(value , key , index) in data'>
                    <div class="row">{{key}}</div>
                    <div class="row">{{value}}</div>
                  </div>
                </div>
              </div>
            </div>
        </div>
        </div>
        <div class="row height45">
            <div class="col">
              <div class="card active">
              <b></b>
              <b></b>
              <b></b>
              <b></b>
               <h4 class="card_title">е®һж—¶ж•°жҚ®</h4>
              <div class="chartpost" ref = 'mychart'>

              </div>
            </div>
        </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>

import echarts from 'echarts'
import Nav from './Nav.vue'


export default {
  name: 'Index',
  components:{Nav},
  data () {
    return {
      msg: 'Welcome to Your Vue.js App',
      chart:null,
      timer:null,
      marker:[],
      data:{
            "еҢ»йҷўеҗҚз§°": "",
            "еһӢеҸ·и§„ж ј": "",
            "зұ»еһӢ": "",
            "еҮәеҺӮзј–еҸ·": "",
            "з”ҹдә§еҺӮе®¶": "",
            "еҢ»йҷўзә§еҲ«": "",
            "зӯүзә§": "",
            "еҢ»йҷўжүҖеңЁеҢәеҺҝ": "",
            "жЈҖе®ҡдәәе‘ҳ": "",
            "ж•°жҚ®жЈҖе®ҡж—Ҙжңҹ": "",
            "иҜҒд№Ұзј–еҸ·": "",
            "жөӢйҮҸжқЎд»¶kv": "",
            "жөӢйҮҸжқЎд»¶mA": "",
            "жөӢйҮҸжқЎд»¶s": "",
            "жөӢйҮҸжқЎд»¶mAs(з§»еҠЁдё“з”Ёпјү": "",
            "йҮҚеӨҚжҖ§": "",
            "йҮҚеӨҚжҖ§и®Ўз®—з»“жһң": "",
            "еҚҠеҖјеұӮ й“қжқҝеҺҡеәҰmmAL": "",
            "еҠ зүҮеҗҺеҚҠеҖјеұӮж•°жҚ®": "",
            "зәҝжҖ§20mAsпјҹ": "",
            "зәҝжҖ§ж•°жҚ®20mAs": "",
            "зәҝжҖ§ж•°жҚ®10mAs": "",
            "зәҝжҖ§и®Ўз®—з»“жһң": ""
        }
    }
  },
  mounted() {
      this.initMap();
      this.ininChart();
      this.initTable()
      this.timer = setInterval(()=>{
          this.pushData()
      }, 1000)
  },
  methods: {
      initMap(){
            var map = new BMap.Map("allmap");
            var map = new BMap.Map("allmap");
            var point = new BMap.Point(116.404, 39.915);
            map.enableScrollWheelZoom();                            //еҗҜз”Ёж»ҡиҪ®ж”ҫеӨ§зј©е°Ҹ
            map.centerAndZoom(point, 11); 
            map.setMapStyle({style:'midnight'});


            var pointList = [
                {
                    j:116.42,
                    w:39.93
                },
                {
                    j:116.37,
                    w:39.92
                },
                {
                    j:116.22,
                    w:39.9
                },
                {
                    j:116.1,
                    w:39.93
                }
            ]
            for(let i = 0 ; i < pointList.length ; i ++){
                var pt = new BMap.Point(pointList[i].j, pointList[i].w);
                var myIcon = new BMap.Icon("https://s2.ax1x.com/2019/05/14/EohY7t.png", new BMap.Size(50,50));
                this.marker.push(new BMap.Marker(pt,{icon:myIcon}));    // еҲӣе»әж ҮжіЁ
                map.addOverlay(this.marker[i]);                             // е°Ҷж ҮжіЁж·»еҠ еҲ°ең°еӣҫдёӯ
                this.marker[i].addEventListener('click' , ()=>{
                    this.data = this.gloData[i];
                    this.ininChart();
                })
            }
      },
      initTable(){
        var index = localStorage.getItem('index') ? parseInt(localStorage.getItem('index')) : 0;
        this.data = this.gloData[index];
      },
      ininChart(){
        

        // еҹәдәҺеҮҶеӨҮеҘҪзҡ„domпјҢеҲқе§ӢеҢ–echartsе®һдҫӢ
        this.chart = echarts.init(this.$refs.mychart);
        var timeArr = [];
        for (var index = 0; index < 30; index++) {
            timeArr.push(index)
        }

        var dataArr = [];

        for (var i = 0; i < 30; i++) {
            dataArr.push(Math.random() * 300);
        }

        // жҢҮе®ҡеӣҫиЎЁзҡ„й…ҚзҪ®йЎ№е’Ңж•°жҚ®
        var option = {
            title: {
                text: "еҚ•дҪҚпјҡ",
                textStyle: {
                    color: "#597d97",
                    fontWeight: 100
                },
                left: 20
            },
            color: ['#3398DB'],
            tooltip: {
                trigger: 'axis',
                axisPointer: { // еқҗж ҮиҪҙжҢҮзӨәеҷЁпјҢеқҗж ҮиҪҙи§ҰеҸ‘жңүж•Ҳ
                    type: 'shadow' // й»ҳи®ӨдёәзӣҙзәҝпјҢеҸҜйҖүдёәпјҡ'line' | 'shadow'
                }
            },
            grid: {
                left: '3%',
                right: '4%',
                bottom: '3%',
                containLabel: true,
                axisLabel: {
                    textStyle: {
                        color: "#597d97"
                    }
                }
            },
            xAxis: [{
                type: 'category',
                data: timeArr,
                axisTick: {
                    alignWithLabel: true
                },
                axisLabel: {
                    textStyle: {
                        color: "#667e9a"
                    }
                },
                axisLine: {
                    lineStyle: {
                        color: "#063d7e"
                    }
                }
            }],
            yAxis: [{
                type: 'value',
                axisLabel: {
                    textStyle: {
                        color: "#667e9a"
                    }
                },
                axisLine: {
                    lineStyle: {
                        color: "#063d7e"
                    }
                }
            }],
            series: [{
                name: 'иҫҗе°„йҮҸ',
                type: 'bar',
                barWidth: '60%',
                data: dataArr,
                itemStyle: {
                    normal: {
                        color: "#20d090"
                    }
                }
            }],
            legend: {
                data: ['иҫҗе°„йҮҸ'],
                textStyle: {
                    color: "#fff"
                }
            }
        };

        // дҪҝз”ЁеҲҡжҢҮе®ҡзҡ„й…ҚзҪ®йЎ№е’Ңж•°жҚ®жҳҫзӨәеӣҫиЎЁгҖӮ
        this.chart.setOption(option);
      },
      pushData(){
        var option = this.chart.getOption();
        var dataArr = option.series[0].data;
        dataArr.shift()
        dataArr.push(Math.random() * 300);
        var timeArr = option.xAxis[0].data;
        timeArr.shift()
        timeArr.push( timeArr[timeArr.length-1] + 1);
        option.series[0].data = dataArr
        option.xAxis[0].data = timeArr
        this.chart.setOption(option);
      }
  },
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
</style>



