<template>
  <div id="app" ref = 'app'>
    <router-view/>
  </div>
</template>

<script>

export default {
  name: 'App',
  data(){
    return {
      fullWidth : null, 
      fullHeight : null
    }
  },
  mounted() {
    this.fullHeight =   `${document.documentElement.clientHeight}`  
    this.fullWidth =   `${document.documentElement.clientWidth}`    
    window.onresize = function temp() {
      this.fullHeight =   `${document.documentElement.clientHeight}`  
      this.fullWidth =   `${document.documentElement.clientWidth}` 
    };

    if(parseInt(this.fullHeight) > parseInt(this.fullWidth)){
      alert('иҜ·ж—ӢиҪ¬жүӢжңә,еңЁжЁӘеұҸдёӢиҝҗиЎҢжӯӨзі»з»ҹ');
    } 

  },
  watch: {
    fullWidth:function(){
      this.renderDisplay()
    }
  },
  methods: {
    renderDisplay : function(){
      var scale = this.fullWidth / 1920 - 0.15;
      this.$refs.app.style.transform = ' translate(-50% , -50%) scale('+scale+')';
    }

  },
}
</script>

<style>

</style>



